-- Repository analytics: daily stats per repository and detailed items

-- Daily aggregated stats per repository
create table if not exists "public"."repository_analytics_daily" (
    "id" bigint generated by default as identity not null,
    "repository_id" bigint not null,
    "class_id" bigint not null,
    "assignment_id" bigint not null,
    "date" date not null,
    "issues_opened" integer not null default 0,
    "issues_closed" integer not null default 0,
    "issue_comments" integer not null default 0,
    "prs_opened" integer not null default 0,
    "pr_review_comments" integer not null default 0,
    "commits" integer not null default 0,
    "updated_at" timestamp with time zone not null default now(),
    constraint repository_analytics_daily_pkey primary key (id),
    constraint repository_analytics_daily_repository_id_fkey foreign key (repository_id) references repositories(id) on delete cascade,
    constraint repository_analytics_daily_class_id_fkey foreign key (class_id) references classes(id) on delete cascade,
    constraint repository_analytics_daily_assignment_id_fkey foreign key (assignment_id) references assignments(id) on delete cascade,
    constraint repository_analytics_daily_unique unique (repository_id, date)
);

-- Detailed items (issues, PRs, commits) with GitHub URLs
create table if not exists "public"."repository_analytics_items" (
    "id" bigint generated by default as identity not null,
    "repository_id" bigint not null,
    "class_id" bigint not null,
    "assignment_id" bigint not null,
    "item_type" text not null check (item_type in ('issue', 'pr', 'commit', 'issue_comment', 'pr_review_comment')),
    "github_id" text not null,
    "title" text,
    "url" text not null,
    "author" text,
    "created_date" date not null,
    "state" text,
    "updated_at" timestamp with time zone not null default now(),
    constraint repository_analytics_items_pkey primary key (id),
    constraint repository_analytics_items_repository_id_fkey foreign key (repository_id) references repositories(id) on delete cascade,
    constraint repository_analytics_items_class_id_fkey foreign key (class_id) references classes(id) on delete cascade,
    constraint repository_analytics_items_assignment_id_fkey foreign key (assignment_id) references assignments(id) on delete cascade,
    constraint repository_analytics_items_unique unique (repository_id, item_type, github_id)
);

-- Track fetch status per assignment (last fetch time, used for rate limiting refresh)
create table if not exists "public"."repository_analytics_fetch_status" (
    "id" bigint generated by default as identity not null,
    "assignment_id" bigint not null,
    "class_id" bigint not null,
    "last_fetched_at" timestamp with time zone,
    "last_requested_at" timestamp with time zone,
    "status" text not null default 'idle' check (status in ('idle', 'fetching', 'completed', 'error')),
    "error_message" text,
    constraint repository_analytics_fetch_status_pkey primary key (id),
    constraint repository_analytics_fetch_status_assignment_id_fkey foreign key (assignment_id) references assignments(id) on delete cascade,
    constraint repository_analytics_fetch_status_class_id_fkey foreign key (class_id) references classes(id) on delete cascade,
    constraint repository_analytics_fetch_status_unique unique (assignment_id)
);

-- Indexes for fast lookups
create index if not exists idx_repo_analytics_daily_assignment on repository_analytics_daily(assignment_id);
create index if not exists idx_repo_analytics_daily_repo on repository_analytics_daily(repository_id);
create index if not exists idx_repo_analytics_items_assignment on repository_analytics_items(assignment_id);
create index if not exists idx_repo_analytics_items_repo on repository_analytics_items(repository_id);
create index if not exists idx_repo_analytics_items_type on repository_analytics_items(item_type);

-- RLS policies
alter table "public"."repository_analytics_daily" enable row level security;
alter table "public"."repository_analytics_items" enable row level security;
alter table "public"."repository_analytics_fetch_status" enable row level security;

-- Instructors and graders can read analytics
create policy "Instructors and graders can read analytics daily"
    on "public"."repository_analytics_daily"
    for select
    using (public.authorizeforclassgrader(class_id) or public.authorizeforclassinstructor(class_id));

create policy "Instructors and graders can read analytics items"
    on "public"."repository_analytics_items"
    for select
    using (public.authorizeforclassgrader(class_id) or public.authorizeforclassinstructor(class_id));

create policy "Instructors and graders can read fetch status"
    on "public"."repository_analytics_fetch_status"
    for select
    using (public.authorizeforclassgrader(class_id) or public.authorizeforclassinstructor(class_id));

-- Service role insert/update (via worker) - no RLS needed for service role, but add explicit policies
create policy "Service role can manage analytics daily"
    on "public"."repository_analytics_daily"
    for all
    using (true)
    with check (true);

create policy "Service role can manage analytics items"
    on "public"."repository_analytics_items"
    for all
    using (true)
    with check (true);

create policy "Service role can manage fetch status"
    on "public"."repository_analytics_fetch_status"
    for all
    using (true)
    with check (true);

-- Enqueue function for the analytics fetch task
create or replace function public.enqueue_repo_analytics_fetch(
    p_class_id bigint,
    p_assignment_id bigint,
    p_org text
) returns bigint
language plpgsql
security definer
as $$
declare
    message_id bigint;
    v_org text;
begin
    -- Resolve org: use p_org if provided, otherwise derive from class
    v_org := nullif(trim(p_org), '');
    if v_org is null then
        select c.github_org into v_org from public.classes c where c.id = p_class_id;
        v_org := nullif(trim(v_org), '');
    end if;
    if v_org is null then
        raise exception 'Class % has no GitHub org configured; cannot enqueue repo analytics fetch', p_class_id;
    end if;

    select pgmq_public.send(
        'async_calls',
        jsonb_build_object(
            'method', 'fetch_repo_analytics',
            'class_id', p_class_id,
            'args', jsonb_build_object(
                'assignment_id', p_assignment_id,
                'org', v_org
            )
        )
    ) into message_id;

    -- Upsert the fetch status
    insert into public.repository_analytics_fetch_status (assignment_id, class_id, last_requested_at, status)
    values (p_assignment_id, p_class_id, now(), 'fetching')
    on conflict (assignment_id)
    do update set last_requested_at = now(), status = 'fetching';

    return message_id;
end;
$$;
